from typing import List, Dict, Any
from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine


def apply_dynamic_filters(
    search_results: List[SearchResult],
    filter_specs: Dict[str, Dict[str, Any]],
    filter_logic: str = "AND"
) -> List[SearchResult]:
    """Apply dynamic metadata filters to search results with configurable logic.

    Args:
        search_results: List of SearchResult objects to filter
        filter_specs: Dictionary of filter specifications.
            Format: {"field_name": {"operator": value}}
            Example: {"category": {"==": "tech"}, "rating": {">=": 4.0}}
        filter_logic: "AND" (all filters must match) or "OR" (any filter matches)

    Returns:
        Filtered list of SearchResult objects
    """
    if not search_results or not filter_specs:
        return search_results

    # Normalize logic value
    logic = filter_logic.strip().upper()
    if logic not in {"AND", "OR"}:
        raise ValueError(f"Unsupported filter_logic '{filter_logic}'. Use 'AND' or 'OR'.")

    # Convert SearchResult objects to dictionaries suitable for MetadataFilterEngine.
    # We assume SearchResult exposes a dict-like or serializable interface; fall back
    # to __dict__ if needed.
    def result_to_dict(res: SearchResult) -> Dict[str, Any]:
        if hasattr(res, "to_dict") and callable(getattr(res, "to_dict")):
            return res.to_dict()
        if hasattr(res, "dict") and callable(getattr(res, "dict")):
            return res.dict()
        # Fallback: shallow copy of __dict__
        return dict(getattr(res, "__dict__", {}))

    results_dicts = [result_to_dict(r) for r in search_results]

    # Initialize metadata filter engine with the provided filter specifications
    engine = MetadataFilterEngine(filter_specs=filter_specs, logic=logic)

    # Compute a boolean mask for which items match
    # We expect the engine to provide a method like `filter_items` that returns indices
    # or a mask. To keep it generic, we use a predicate-based interface if available.
    matched_indices = []

    if hasattr(engine, "match") and callable(getattr(engine, "match")):
        # Per-item predicate style: engine.match(record_dict) -> bool
        for idx, item in enumerate(results_dicts):
            if engine.match(item):
                matched_indices.append(idx)
    elif hasattr(engine, "filter") and callable(getattr(engine, "filter")):
        # Bulk style: engine.filter(list_of_dicts) -> list_of_indices or list_of_items
        filtered = engine.filter(results_dicts)
        # If the engine returns the original dicts, map them back to indices.
        if filtered and isinstance(filtered[0], dict):
            dict_to_index = {id(d): i for i, d in enumerate(results_dicts)}
            for d in filtered:
                idx = dict_to_index.get(id(d))
                if idx is not None:
                    matched_indices.append(idx)
        else:
            # Assume it returned indices
            matched_indices = list(filtered)
    else:
        # Fallback: implement logic using generic evaluation if engine exposes `evaluate`
        # or equivalent. If not available, raise to avoid silently incorrect behavior.
        if hasattr(engine, "evaluate") and callable(getattr(engine, "evaluate")):
            for idx, item in enumerate(results_dicts):
                if engine.evaluate(item):
                    matched_indices.append(idx)
        else:
            raise RuntimeError(
                "MetadataFilterEngine does not expose a known filtering interface "
                "('match', 'filter', or 'evaluate')."
            )

    # Preserve original SearchResult objects, filtered by matched indices
    matched_set = set(matched_indices)
    return [res for i, res in enumerate(search_results) if i in matched_set]
