from typing import List, Dict, Any
from leann.api import PassageManager
from pathlib import Path
import json


def filter_passages_by_metadata_criteria(
    index_path: str,
    metadata_criteria: Dict[str, Any]
) -> List[Dict[str, Any]]:
    """Retrieve all passages from an index that match metadata criteria.

    Args:
        index_path: Path to the LEANN index directory
        metadata_criteria: Dictionary of metadata field-value pairs to match.
            Example: {"category": "tech", "rating": 5.0}
            All criteria must match (AND logic)

    Returns:
        List of passage dictionaries that match all criteria.
        Returns an empty list if no passages match or if the passages file
        does not exist.
    """
    # Ensure index_path is a Path
    index_dir = Path(index_path)

    # Use PassageManager to locate the passages data file
    try:
        pm = PassageManager(index_dir)
    except Exception:
        # If the PassageManager cannot be initialized, treat as no passages
        return []

    # Attempt to get the passages file path from the PassageManager.
    # The actual attribute/method name may vary depending on the leann version.
    # We try common options and fall back to conventional filenames.
    passages_file: Path | None = None

    # Try attribute commonly used in LEANN for passages storage
    for attr_name in ("passages_path", "passage_path", "passages_file", "passage_file"):
        if hasattr(pm, attr_name):
            candidate = getattr(pm, attr_name)
            if isinstance(candidate, (str, Path)):
                candidate = Path(candidate)
            if isinstance(candidate, Path):
                passages_file = candidate
                break

    # If PassageManager doesn’t expose it, try standard locations
    if passages_file is None:
        # Typical names: passages.jsonl, passages.json, passages.ndjson
        for name in ("passages.jsonl", "passages.json", "passages.ndjson"):
            candidate = index_dir / name
            if candidate.is_file():
                passages_file = candidate
                break

    # If we still don't have a file or it doesn't exist, return empty list
    if passages_file is None or not passages_file.is_file():
        return []

    passages: List[Dict[str, Any]] = []

    # Load passages; support JSONL/NDJSON (one JSON object per line)
    # and plain JSON array.
    try:
        if passages_file.suffix.lower() in {".jsonl", ".ndjson"}:
            with passages_file.open("r", encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        passage = json.loads(line)
                        passages.append(passage)
                    except json.JSONDecodeError:
                        # Skip malformed lines
                        continue
        else:
            with passages_file.open("r", encoding="utf-8") as f:
                data = json.load(f)
                # If it's an array, use directly; if it's a dict with a known
                # key (e.g., "passages"), extract that.
                if isinstance(data, list):
                    passages = data
                elif isinstance(data, dict):
                    if "passages" in data and isinstance(data["passages"], list):
                        passages = data["passages"]
                    else:
                        # If structure is unexpected, treat as no passages
                        passages = []
                else:
                    passages = []
    except (OSError, json.JSONDecodeError):
        # Any issue reading or parsing the file -> treated as no passages
        return []

    # If no criteria, all passages "match"
    if not metadata_criteria:
        return passages

    def matches_criteria(passage: Dict[str, Any]) -> bool:
        meta = passage.get("metadata", {})
        if not isinstance(meta, dict):
            return False
        for key, value in metadata_criteria.items():
            if key not in meta or meta[key] != value:
                return False
        return True

    # Filter passages using AND logic on all metadata_criteria
    filtered = [p for p in passages if matches_criteria(p)]

    return filtered
